#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <cstdint>
#include <cuda_runtime.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

#define CHECK_CUDA(call)                                                     \
  do {                                                                       \
    cudaError_t err__ = (call);                                              \
    if (err__ != cudaSuccess) {                                              \
      fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__,       \
              cudaGetErrorString(err__));                                    \
      exit(EXIT_FAILURE);                                                    \
    }                                                                        \
  } while (0)

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T * __restrict__ mask,
                              const T * __restrict__ in,
                                    T * __restrict__ out,
                              const int input_width,
                              const int mask_width)
{
  int i = blockIdx.x * BLOCK_SIZE + threadIdx.x;
  if (i < input_width) {
    int start = i - mask_width / 2;
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T, int BLOCK_SIZE>
void conv1d(const T * __restrict__ mask,
            const T * __restrict__ in,
                  T * __restrict__ out,
            const int input_width,
            const int mask_width)
{
  dim3 block(BLOCK_SIZE);
  dim3 grid((input_width + BLOCK_SIZE - 1) / BLOCK_SIZE);
  conv1d_kernel<T, BLOCK_SIZE><<<grid, block>>>(mask, in, out, input_width, mask_width);
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T * __restrict__ mask,
                                    const T * __restrict__ in,
                                          T * __restrict__ out,
                                    const int input_width,
                                    const int mask_width)
{
  __shared__ T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = BLOCK_SIZE;
  int i = bid * dim + lid;

  int n = mask_width / 2;

  int halo_left = (bid - 1) * dim + lid;
  if (lid >= dim - n) {
    tile[lid - (dim - n)] = halo_left < 0 ? (T)0 : in[halo_left];
  }

  tile[n + lid] = (i < input_width) ? in[i] : (T)0;

  int halo_right = (bid + 1) * dim + lid;
  if (lid < n) {
    tile[lid + dim + n] = halo_right >= input_width ? (T)0 : in[halo_right];
  }

  __syncthreads();

  if (i < input_width) {
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      s += tile[lid + j] * mask[j];
    }
    out[i] = s;
  }
}

template<typename T, int BLOCK_SIZE>
void conv1d_tiled(const T *__restrict__ mask,
                  const T *__restrict__ in,
                        T *__restrict__ out,
                  const int input_width,
                  const int mask_width)
{
  dim3 block(BLOCK_SIZE);
  dim3 grid(input_width / BLOCK_SIZE);
  conv1d_tiled_kernel<T, BLOCK_SIZE><<<grid, block>>>(mask, in, out, input_width, mask_width);
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T *__restrict__ mask,
                                            const T *__restrict__ in,
                                                  T *__restrict__ out,
                                            const int input_width,
                                            const int mask_width)
{
  __shared__ T tile[BLOCK_SIZE];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = BLOCK_SIZE;
  int i = bid * dim + lid;

  tile[lid] = (i < input_width) ? in[i] : (T)0;
  __syncthreads();

  if (i < input_width) {
    int this_tile_start = bid * dim;
    int next_tile_start = (bid + 1) * dim;
    int start = i - (mask_width / 2);
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      int in_index = start + j;
      if (in_index >= 0 && in_index < input_width) {
        if (in_index >= this_tile_start && in_index < next_tile_start) {
          s += tile[lid + j - (mask_width / 2)] * mask[j];
        } else {
          s += in[in_index] * mask[j];
        }
      }
    }
    out[i] = s;
  }
}

template<typename T, int BLOCK_SIZE>
void conv1d_tiled_caching(const T *__restrict__ mask,
                          const T *__restrict__ in,
                                T *__restrict__ out,
                          const int input_width,
                          const int mask_width)
{
  dim3 block(BLOCK_SIZE);
  dim3 grid(input_width / BLOCK_SIZE);
  conv1d_tiled_caching_kernel<T, BLOCK_SIZE><<<grid, block>>>(mask, in, out, input_width, mask_width);
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = (size_t)input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a = nullptr;
  T *d_b = nullptr;
  T *d_mask = nullptr;

  CHECK_CUDA(cudaMalloc((void **)&d_a, size_bytes));
  CHECK_CUDA(cudaMalloc((void **)&d_b, size_bytes));
  CHECK_CUDA(cudaMalloc((void **)&d_mask, (size_t)mask_width * sizeof(T)));

  CHECK_CUDA(cudaMemcpy(d_a, a, size_bytes, cudaMemcpyHostToDevice));
  CHECK_CUDA(cudaMemcpy(d_mask, mask, (size_t)mask_width * sizeof(T), cudaMemcpyHostToDevice));

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    CHECK_CUDA(cudaDeviceSynchronize());
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d<T, 64>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d<T, 128>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d<T, 256>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d<T, 512>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case 1024: {conv1d<T, 1024>(d_mask, d_a, d_b, input_width, mask_width); break;}
      }
    }
    CHECK_CUDA(cudaGetLastError());
    CHECK_CUDA(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    CHECK_CUDA(cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost));
    reference(a, b, mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    CHECK_CUDA(cudaDeviceSynchronize());
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled<T, 64>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d_tiled<T, 128>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d_tiled<T, 256>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d_tiled<T, 512>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case 1024: {conv1d_tiled<T, 1024>(d_mask, d_a, d_b, input_width, mask_width); break;}
      }
    }
    CHECK_CUDA(cudaGetLastError());
    CHECK_CUDA(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    CHECK_CUDA(cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost));
    reference(a, b, mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    CHECK_CUDA(cudaDeviceSynchronize());
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled_caching<T, 64>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d_tiled_caching<T, 128>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d_tiled_caching<T, 256>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d_tiled_caching<T, 512>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case 1024: {conv1d_tiled_caching<T, 1024>(d_mask, d_a, d_b, input_width, mask_width); break;}
      }
    }
    CHECK_CUDA(cudaGetLastError());
    CHECK_CUDA(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    CHECK_CUDA(cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost));
    reference(a, b, mask, input_width, mask_width);
  }

  CHECK_CUDA(cudaFree(d_a));
  CHECK_CUDA(cudaFree(d_b));
  CHECK_CUDA(cudaFree(d_mask));

  free(a);
  free(b);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
